import { fetchAuthSession } from &#34;aws-amplify/auth&#34;; const rawApiBaseUrl = process.env.NEXT_PUBLIC_API_BASE_URL; if (!rawApiBaseUrl) { throw new Error( &#34;Missing NEXT_PUBLIC_API_BASE_URL.&#34; ); } const API_BASE_URL = rawApiBaseUrl.replace( /\/+$/, &#34;&#34; ); type ApiErrorBody = { message?: string; error?: string; }; async function getJwtToken(): Promise&lt;string&gt; { let session = await fetchAuthSession(); let token = session.tokens?.idToken?.toString() ?? session.tokens?.accessToken?.toString(); if (!token) { session = await fetchAuthSession({ forceRefresh: true, }); token = session.tokens?.idToken?.toString() ?? session.tokens?.accessToken?.toString(); } if (!token) { throw new Error( &#34;The session has no JWT. &#34; + &#34;Please sign out and sign in again.&#34; ); } return token; } export async function apiGet&lt;T&gt;( path: string ): Promise&lt;T&gt; { const jwtToken = await getJwtToken(); const response = await fetch( `${API_BASE_URL}${path}`, { method: &#34;GET&#34;, headers: { Authorization: `Bearer ${jwtToken}`, Accept: &#34;application/json&#34;, }, cache: &#34;no-store&#34;, } ); const responseText = await response.text(); let responseBody: unknown = {}; if (responseText) { try { responseBody = JSON.parse(responseText); } catch { responseBody = { message: responseText, }; } } if (!response.ok) { const errorBody = responseBody as ApiErrorBody; throw new Error( errorBody.message || errorBody.error || `API returned error ${response.status}.` ); } return responseBody as T; }

We will test the Lambda function independently to verify its routing and database interactions before connecting it to Amazon API Gateway.
Test 1 — GET /rooms Select the Test tab in your Lambda function. Click Create new event. For Event name, enter: test_get_rooms Paste the following JSON payload: { &ldquo;version&rdquo;: &ldquo;2.0&rdquo;, &ldquo;routeKey&rdquo;: &ldquo;GET /rooms&rdquo;, &ldquo;rawPath&rdquo;: &ldquo;/rooms&rdquo;, &ldquo;requestContext&rdquo;: { &ldquo;http&rdquo;: { &ldquo;method&rdquo;: &ldquo;GET&rdquo;, &ldquo;path&rdquo;: &ldquo;/rooms&rdquo; } } }
Click Save and then click Test. Expected Result:
statusCode = 200 success = true The body must contain room profile items with attributes similar to: PK = ROOM#lab-01, SK = PROFILE. (Note: The body is returned as a JSON string with escaped quotes \&quot;; this is standard behavior for a Lambda proxy integration response). Test 2 — GET /telemetry Create a new test event named: test_get_telemetry Paste the following JSON payload: { &ldquo;version&rdquo;: &ldquo;2.0&rdquo;, &ldquo;routeKey&rdquo;: &ldquo;GET /telemetry&rdquo;, &ldquo;rawPath&rdquo;: &ldquo;/telemetry&rdquo;, &ldquo;queryStringParameters&rdquo;: { &ldquo;roomId&rdquo;: &ldquo;lab-01&rdquo;, &ldquo;limit&rdquo;: &ldquo;20&rdquo; }, &ldquo;requestContext&rdquo;: { &ldquo;http&rdquo;: { &ldquo;method&rdquo;: &ldquo;GET&rdquo;, &ldquo;path&rdquo;: &ldquo;/telemetry&rdquo; } } }
Click Test. Expected Result:
statusCode = 200 roomId = lab-01 count &gt; 0 The items array must include items with sort keys starting with: TELEMETRY# (Note: DynamoDB stores items with the same partition key ordered by their sort key. The function uses ScanIndexForward=False to fetch the latest records first). Test 3 — GET /alerts Create a new test event named: test_get_alerts Paste the following JSON payload: { &ldquo;version&rdquo;: &ldquo;2.0&rdquo;, &ldquo;routeKey&rdquo;: &ldquo;GET /alerts&rdquo;, &ldquo;rawPath&rdquo;: &ldquo;/alerts&rdquo;, &ldquo;queryStringParameters&rdquo;: { &ldquo;roomId&rdquo;: &ldquo;lab-01&rdquo;, &ldquo;limit&rdquo;: &ldquo;20&rdquo; }, &ldquo;requestContext&rdquo;: { &ldquo;http&rdquo;: { &ldquo;method&rdquo;: &ldquo;GET&rdquo;, &ldquo;path&rdquo;: &ldquo;/alerts&rdquo; } } }
Click Test. Expected Result:
statusCode = 200 roomId = lab-01 The items array must include items with sort keys starting with: ALERT# Test 4 — GET /reports Create a new test event named: test_get_reports Paste the following JSON payload: { &ldquo;version&rdquo;: &ldquo;2.0&rdquo;, &ldquo;routeKey&rdquo;: &ldquo;GET /reports&rdquo;, &ldquo;rawPath&rdquo;: &ldquo;/reports&rdquo;, &ldquo;queryStringParameters&rdquo;: { &ldquo;limit&rdquo;: &ldquo;20&rdquo; }, &ldquo;requestContext&rdquo;: { &ldquo;http&rdquo;: { &ldquo;method&rdquo;: &ldquo;GET&rdquo;, &ldquo;path&rdquo;: &ldquo;/reports&rdquo; } } }
Click Test. Expected Result at this stage:
statusCode = 200 count = 0 message = Chưa có báo cáo. (Note: This is expected and not an error because the Report Generator function has not been created yet). Test 5 — GET /reports/{date} Create a new test event named: test_get_report_by_date Paste the following JSON payload: { &ldquo;version&rdquo;: &ldquo;2.0&rdquo;, &ldquo;routeKey&rdquo;: &ldquo;GET /reports/{date}&rdquo;, &ldquo;rawPath&rdquo;: &ldquo;/reports/2026-07-03&rdquo;, &ldquo;pathParameters&rdquo;: { &ldquo;date&rdquo;: &ldquo;2026-07-03&rdquo; }, &ldquo;requestContext&rdquo;: { &ldquo;http&rdquo;: { &ldquo;method&rdquo;: &ldquo;GET&rdquo;, &ldquo;path&rdquo;: &ldquo;/reports/2026-07-03&rdquo; } } }
Click Test. Expected Result at this stage:
statusCode = 404 message = Chưa có báo cáo cho ngày này. (Note: This is also the correct expected output for the current phase).

