&#34;use client&#34;; import { useCallback, useEffect, useState } from &#34;react&#34;; import { apiGet } from &#34;@/lib/api&#34;; type DataItem = Record&lt;string, unknown&gt;; type ListResponse = { success?: boolean; count?: number; roomId?: string; items?: DataItem[]; message?: string; }; type ReportDetailResponse = { success?: boolean; item?: DataItem; downloadUrl?: string; expiresIn?: number; message?: string; }; type DashboardProps = { email: string; onSignOut: () =&gt; Promise&lt;void&gt;; }; function displayValue(value: unknown, fallback = &#34;-&#34;): string { if (value === null || value === undefined || value === &#34;&#34;) { return fallback; } if (typeof value === &#34;boolean&#34;) { return value ? &#34;Yes&#34; : &#34;No&#34;; } return String(value); } function getRoomId(item: DataItem): string { if (typeof item.roomId === &#34;string&#34;) return item.roomId; if (typeof item.PK === &#34;string&#34; &amp;&amp; item.PK.startsWith(&#34;ROOM#&#34;)) { return item.PK.replace(&#34;ROOM#&#34;, &#34;&#34;); } return &#34;lab-01&#34;; } function getReportDate(item: DataItem): string { if (typeof item.date === &#34;string&#34;) return item.date; if (typeof item.SK === &#34;string&#34; &amp;&amp; item.SK.startsWith(&#34;REPORT#&#34;)) { return item.SK.replace(&#34;REPORT#&#34;, &#34;&#34;); } return &#34;&#34;; } function SummaryCard({ title, value, description, }: { title: string; value: number | string; description: string; }) { return ( &lt;div className=&#34;rounded-2xl border border-slate-200 bg-white p-5 shadow-sm&#34;&gt; &lt;p className=&#34;text-sm font-medium text-slate-500&#34;&gt;{title}&lt;/p&gt; &lt;p className=&#34;mt-2 text-3xl font-bold text-slate-900&#34;&gt;{value}&lt;/p&gt; &lt;p className=&#34;mt-2 text-sm text-slate-500&#34;&gt;{description}&lt;/p&gt; &lt;/div&gt; ); } export default function Dashboard({ email, onSignOut }: DashboardProps) { const [selectedRoom, setSelectedRoom] = useState(&#34;lab-01&#34;); const [rooms, setRooms] = useState&lt;DataItem[]&gt;([]); const [telemetry, setTelemetry] = useState&lt;DataItem[]&gt;([]); const [alerts, setAlerts] = useState&lt;DataItem[]&gt;([]); const [reports, setReports] = useState&lt;DataItem[]&gt;([]); const [loading, setLoading] = useState(true); const [error, setError] = useState(&#34;&#34;); const [downloadingDate, setDownloadingDate] = useState(&#34;&#34;); const loadDashboard = useCallback(async () =&gt; { setLoading(true); setError(&#34;&#34;); try { const [roomsResult, telemetryResult, alertsResult, reportsResult] = await Promise.all([ apiGet&lt;ListResponse&gt;(&#34;/rooms&#34;), apiGet&lt;ListResponse&gt;( `/telemetry?roomId=${encodeURIComponent(selectedRoom)}&amp;limit=20` ), apiGet&lt;ListResponse&gt;( `/alerts?roomId=${encodeURIComponent(selectedRoom)}&amp;limit=20` ), apiGet&lt;ListResponse&gt;(&#34;/reports&#34;), ]); const roomItems = roomsResult.items ?? []; setRooms(roomItems); setTelemetry(telemetryResult.items ?? []); setAlerts(alertsResult.items ?? []); setReports(reportsResult.items ?? []); if ( roomItems.length &gt; 0 &amp;&amp; !roomItems.some((room) =&gt; getRoomId(room) === selectedRoom) ) { setSelectedRoom(getRoomId(roomItems[0])); } } catch (requestError) { setError( requestError instanceof Error ? requestError.message : &#34;Unable to load Dashboard data.&#34; ); } finally { setLoading(false); } }, [selectedRoom]); useEffect(() =&gt; { void loadDashboard(); }, [loadDashboard]); async function downloadReport(report: DataItem) { const reportDate = getReportDate(report); if (!reportDate) { setError(&#34;Report metadata has no valid date.&#34;); return; } setDownloadingDate(reportDate); setError(&#34;&#34;); const downloadTab = window.open(&#34;about:blank&#34;, &#34;_blank&#34;); if (downloadTab) downloadTab.opener = null; try { const result = await apiGet&lt;ReportDetailResponse&gt;( `/reports/${encodeURIComponent(reportDate)}` ); if (!result.downloadUrl) { throw new Error(result.message || &#34;API did not return a downloadUrl.&#34;); } if (downloadTab) { downloadTab.location.href = result.downloadUrl; } else { window.location.href = result.downloadUrl; } } catch (requestError) { downloadTab?.close(); setError( requestError instanceof Error ? requestError.message : &#34;Unable to download the report.&#34; ); } finally { setDownloadingDate(&#34;&#34;); } } return ( &lt;div className=&#34;min-h-screen bg-slate-100&#34;&gt; &lt;header className=&#34;border-b border-slate-800 bg-slate-950 text-white&#34;&gt; &lt;div className=&#34;mx-auto flex max-w-7xl items-center justify-between px-6 py-5&#34;&gt; &lt;div&gt; &lt;p className=&#34;text-xs font-semibold uppercase tracking-[0.2em] text-emerald-400&#34;&gt; AWS Serverless Project &lt;/p&gt; &lt;h1 className=&#34;mt-1 text-xl font-bold&#34;&gt; Smart Home Energy Waste Monitoring &lt;/h1&gt; &lt;/div&gt; &lt;div className=&#34;flex items-center gap-4&#34;&gt; &lt;div className=&#34;hidden text-right sm:block&#34;&gt; &lt;p className=&#34;text-sm font-medium&#34;&gt;{email}&lt;/p&gt; &lt;p className=&#34;text-xs text-slate-400&#34;&gt;Cognito authenticated&lt;/p&gt; &lt;/div&gt; &lt;button type=&#34;button&#34; onClick={() =&gt; void onSignOut()} className=&#34;rounded-lg border border-slate-600 px-4 py-2 text-sm font-medium hover:bg-slate-800&#34; &gt; Sign out &lt;/button&gt; &lt;/div&gt; &lt;/div&gt; &lt;/header&gt; &lt;main className=&#34;mx-auto max-w-7xl space-y-8 px-6 py-8&#34;&gt; &lt;section className=&#34;flex flex-col justify-between gap-4 rounded-2xl bg-emerald-700 p-6 text-white shadow-lg md:flex-row md:items-center&#34;&gt; &lt;div&gt; &lt;h2 className=&#34;text-2xl font-bold&#34;&gt;Energy Monitoring Dashboard&lt;/h2&gt; &lt;p className=&#34;mt-2 text-sm text-emerald-50&#34;&gt; Track power usage, waste alerts, and daily reports. &lt;/p&gt; &lt;/div&gt; &lt;div className=&#34;flex flex-wrap items-center gap-3&#34;&gt; &lt;label htmlFor=&#34;room&#34; className=&#34;text-sm font-medium&#34;&gt; Room: &lt;/label&gt; &lt;select id=&#34;room&#34; value={selectedRoom} onChange={(event) =&gt; setSelectedRoom(event.target.value)} className=&#34;rounded-lg bg-white px-4 py-2 text-sm text-slate-900&#34; &gt; {rooms.length === 0 &amp;&amp; &lt;option value=&#34;lab-01&#34;&gt;lab-01&lt;/option&gt;} {rooms.map((room, index) =&gt; { const roomId = getRoomId(room); return ( &lt;option key={`${roomId}-${index}`} value={roomId}&gt; {displayValue(room.roomName ?? room.name ?? roomId)} &lt;/option&gt; ); })} &lt;/select&gt; &lt;button type=&#34;button&#34; onClick={() =&gt; void loadDashboard()} className=&#34;rounded-lg bg-white px-4 py-2 text-sm font-semibold text-emerald-700&#34; &gt; Refresh &lt;/button&gt; &lt;/div&gt; &lt;/section&gt; {error &amp;&amp; ( &lt;div className=&#34;rounded-xl border border-red-200 bg-red-50 p-4 text-sm text-red-700&#34;&gt; {error} &lt;/div&gt; )} &lt;section className=&#34;grid gap-4 md:grid-cols-2 xl:grid-cols-4&#34;&gt; &lt;SummaryCard title=&#34;Rooms&#34; value={rooms.length} description=&#34;Configured rooms&#34; /&gt; &lt;SummaryCard title=&#34;Telemetry&#34; value={telemetry.length} description=&#34;Last 20 samples&#34; /&gt; &lt;SummaryCard title=&#34;Alerts&#34; value={alerts.length} description=&#34;Latest alerts&#34; /&gt; &lt;SummaryCard title=&#34;Reports&#34; value={reports.length} description=&#34;Generated reports&#34; /&gt; &lt;/section&gt; {loading ? ( &lt;div className=&#34;rounded-2xl bg-white p-10 text-center text-slate-500 shadow-sm&#34;&gt; Loading data from API Gateway... &lt;/div&gt; ) : ( &lt;&gt; &lt;section className=&#34;rounded-2xl bg-white shadow-sm&#34;&gt; &lt;div className=&#34;border-b border-slate-200 px-6 py-4&#34;&gt; &lt;h2 className=&#34;text-lg font-bold&#34;&gt;Latest Telemetry&lt;/h2&gt; &lt;/div&gt; &lt;div className=&#34;overflow-x-auto&#34;&gt; &lt;table className=&#34;min-w-full text-left text-sm&#34;&gt; &lt;thead className=&#34;bg-slate-50 text-slate-600&#34;&gt; &lt;tr&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Time&lt;/th&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Device&lt;/th&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Power&lt;/th&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Status&lt;/th&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Occupied&lt;/th&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Waste&lt;/th&gt; &lt;/tr&gt; &lt;/thead&gt; &lt;tbody className=&#34;divide-y divide-slate-100&#34;&gt; {telemetry.map((item, index) =&gt; ( &lt;tr key={displayValue(item.SK, String(index))}&gt; &lt;td className=&#34;whitespace-nowrap px-6 py-3&#34;&gt; {displayValue(item.timestamp)} &lt;/td&gt; &lt;td className=&#34;px-6 py-3&#34;&gt; {displayValue(item.deviceName ?? item.deviceId)} &lt;/td&gt; &lt;td className=&#34;px-6 py-3 font-medium&#34;&gt; {displayValue(item.powerW)} W &lt;/td&gt; &lt;td className=&#34;px-6 py-3&#34;&gt; {displayValue(item.deviceStatus)} &lt;/td&gt; &lt;td className=&#34;px-6 py-3&#34;&gt; {displayValue(item.occupancy)} &lt;/td&gt; &lt;td className=&#34;px-6 py-3&#34;&gt; {displayValue(item.isWaste)} &lt;/td&gt; &lt;/tr&gt; ))} {telemetry.length === 0 &amp;&amp; ( &lt;tr&gt; &lt;td colSpan={6} className=&#34;px-6 py-8 text-center text-slate-500&#34;&gt; No telemetry yet. &lt;/td&gt; &lt;/tr&gt; )} &lt;/tbody&gt; &lt;/table&gt; &lt;/div&gt; &lt;/section&gt; &lt;section className=&#34;rounded-2xl bg-white shadow-sm&#34;&gt; &lt;div className=&#34;border-b border-slate-200 px-6 py-4&#34;&gt; &lt;h2 className=&#34;text-lg font-bold&#34;&gt;Waste Alerts&lt;/h2&gt; &lt;/div&gt; &lt;div className=&#34;overflow-x-auto&#34;&gt; &lt;table className=&#34;min-w-full text-left text-sm&#34;&gt; &lt;thead className=&#34;bg-slate-50 text-slate-600&#34;&gt; &lt;tr&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Time&lt;/th&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Device&lt;/th&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Power&lt;/th&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Message&lt;/th&gt; &lt;/tr&gt; &lt;/thead&gt; &lt;tbody className=&#34;divide-y divide-slate-100&#34;&gt; {alerts.map((item, index) =&gt; ( &lt;tr key={displayValue(item.SK, String(index))}&gt; &lt;td className=&#34;whitespace-nowrap px-6 py-3&#34;&gt; {displayValue(item.timestamp)} &lt;/td&gt; &lt;td className=&#34;px-6 py-3&#34;&gt; {displayValue(item.deviceName ?? item.deviceId)} &lt;/td&gt; &lt;td className=&#34;px-6 py-3 font-medium text-red-600&#34;&gt; {displayValue(item.powerW)} W &lt;/td&gt; &lt;td className=&#34;px-6 py-3&#34;&gt; {displayValue( item.message ?? item.reason ?? &#34;Energy waste detected&#34; )} &lt;/td&gt; &lt;/tr&gt; ))} {alerts.length === 0 &amp;&amp; ( &lt;tr&gt; &lt;td colSpan={4} className=&#34;px-6 py-8 text-center text-slate-500&#34;&gt; No alerts yet. &lt;/td&gt; &lt;/tr&gt; )} &lt;/tbody&gt; &lt;/table&gt; &lt;/div&gt; &lt;/section&gt; &lt;section className=&#34;rounded-2xl bg-white shadow-sm&#34;&gt; &lt;div className=&#34;border-b border-slate-200 px-6 py-4&#34;&gt; &lt;h2 className=&#34;text-lg font-bold&#34;&gt;Energy Reports&lt;/h2&gt; &lt;/div&gt; &lt;div className=&#34;overflow-x-auto&#34;&gt; &lt;table className=&#34;min-w-full text-left text-sm&#34;&gt; &lt;thead className=&#34;bg-slate-50 text-slate-600&#34;&gt; &lt;tr&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Date&lt;/th&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Telemetry&lt;/th&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Alerts&lt;/th&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Energy&lt;/th&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Avg. Power&lt;/th&gt; &lt;th className=&#34;px-6 py-3&#34;&gt;Action&lt;/th&gt; &lt;/tr&gt; &lt;/thead&gt; &lt;tbody className=&#34;divide-y divide-slate-100&#34;&gt; {reports.map((item, index) =&gt; { const reportDate = getReportDate(item); return ( &lt;tr key={reportDate || String(index)}&gt; &lt;td className=&#34;px-6 py-3 font-medium&#34;&gt; {displayValue(reportDate)} &lt;/td&gt; &lt;td className=&#34;px-6 py-3&#34;&gt; {displayValue(item.telemetryCount)} &lt;/td&gt; &lt;td className=&#34;px-6 py-3&#34;&gt; {displayValue(item.alertCount)} 